export type KBSection = { id: string; title: string; keywords: string[]; content: string };

export const CORE_PRODUCTS: string = "PRODUCTS, QUALIFYING & LOAN PROCESS — Penny core reference.\n\nPRODUCTS split into government (FHA, VA, USDA), conventional (conforming to Fannie/Freddie limits, or jumbo above them), and non-agency/Non-QM (DSCR/investor, bank-statement, fix-and-flip, bridge). Every mortgage sits on a fixed-rate or adjustable-rate (ARM) base. An ARM rate = index + margin (the fully indexed rate); underwriters qualify the borrower at the higher fully indexed rate, and no part of an ARM may be called \"fixed.\" FHA insures the lender (upfront UFMIP + monthly MIP), allows as little as 3.5% down (580+ score), is assumable, lenient on credit, but strict on property condition; MIP usually lasts the life of the loan at high LTV. VA serves eligible veterans and surviving spouses: 0% down, no monthly MI, a one-time funding fee (waived for a 10%+ service-connected disability), back-end DTI plus a residual-income test, and a required Certificate of Eligibility. USDA is for eligible rural properties with household income at or below 115% of area median: 0% down, upfront + annual guarantee fee. Conventional: 620 minimum score, as little as 3% down, PMI when LTV exceeds 80%, PMI cancelable by request at 80% and auto-terminated at 78% under the Homeowners Protection Act. Jumbo exceeds annually-set FHFA conforming limits with tighter credit/reserve rules.\n\nQUALIFYING = the 4 Cs: Credit, Capacity (income/DTI), Capital (assets), Collateral (appraisal). Credit uses a tri-merge (Experian, Equifax, TransUnion); one borrower uses the middle score, multiple borrowers use the lowest middle (representative) score. Income generally needs a 2-year history: stable income counts as-is; variable income (commission, bonus, overtime, self-employment) is averaged over 2 years. Self-employed = 25%+ business ownership, requiring business and personal returns and using net/AGI. DTI has a front-end (housing ÷ income) and back-end (all debts ÷ income); rough guidelines FHA 31/43, VA 41 back-end + residual, USDA 29/41, conventional up to ~50% via automated underwriting (DU/LPA). Assets and down payment must be sourced and generally 60-day seasoned; gift funds are allowed with a gift letter and no repayment; down-payment assistance runs through state/county/city programs. LTV = loan ÷ lesser of price or appraised value. Reserves = months of PITI remaining after closing.\n\nPROCESS/TIMELINE: an application exists once the 6 ALIENS items are in hand (Address, Loan amount, Income, Estimated value, Name, SSN) → Loan Estimate within 3 business days → borrower gives Intent to Proceed (only then may fees beyond a credit-report fee be charged) → processing, appraisal, underwriting → conditional approval → clear-to-close → Closing Disclosure received at least 3 business days before consummation → signing → funding. A refinance of a primary residence carries a 3-business-day right of rescission; purchases do not. The underwriter (never Penny) makes the final approve/deny decision and cannot be pressured; appraiser independence is law, so Penny never contacts the appraiser or influences value.\n\nFAIR LENDING: Fetti Financial Services is an Equal Housing Opportunity lender (NMLS #2267023). Everyone creditworthy may apply; decisions rest on creditworthiness and program guidelines, never on race, color, religion, national origin, sex, marital status, age, disability, or receipt of public assistance. Penny never quotes a specific rate, APR, payment, or term and never promises approval — those come only from a licensed human loan officer and the underwriter after full review.";

export const CORE_LAW: string = "FEDERAL LAW, DISCLOSURES & COMPLIANCE — Penny's core reference. Fetti Financial Services, NMLS #2267023. Equal Housing Opportunity lender; we serve every creditworthy applicant fairly. Never quote a specific rate, APR, payment, points, or term, and never promise approval — only a licensed loan officer discusses pricing and an underwriter decides.\n\nTILA / Reg Z (1968, CFPB-enforced) is the transparency backbone. It requires disclosure of the finance charge and the APR — the all-in yearly cost of credit (interest PLUS lender/rate-related fees like origination, points, prepaid interest, lender's title, and mortgage insurance), which is why APR usually runs higher than the note rate. Under TILA sit HOEPA, HPML, QM, ATR, LO Compensation, advertising rules, rescission, and TRID.\n\nTRID merged the old GFE/HUD-1 into two forms: the Loan Estimate (delivered within 3 business days of a complete application) and the Closing Disclosure (received at least 3 business days before consummation). A complete application = six items (ALIENS): Address, Loan amount, Income, Estimate of value, Name, SSN. No fee beyond a bona-fide credit-report fee before the borrower states intent to proceed. Closing can't happen sooner than 7 business days after the LE. Fees fall in three tolerance buckets: zero, 10% cumulative, and no-tolerance. Signing the LE or CD only confirms receipt — never acceptance.\n\nRight of rescission (TILA): a 3-business-day right to cancel, ONLY on a refinance or home-equity loan on the borrower's primary residence — never on a purchase, second home, or investment property. Any owner can rescind, and it voids the deal for everyone.\n\nRESPA / Reg X (1974): educates borrowers on settlement costs, bans Section 8 kickbacks and referral fees, requires AfBA disclosure, limits escrow cushion (2 months), and governs servicing transfers (goodbye letter 15 days before, hello letter within 15 days after; 60-day late-fee grace).\n\nFair lending is non-negotiable. ECOA / Reg B bars discrimination by race, color, religion, national origin, sex (incl. sexual orientation), marital status, age, or public-assistance income; everyone creditworthy may apply. The Fair Housing Act adds disability. HMDA / Reg C collects lending data to detect redlining. Never ask about race/sex except for HMDA monitoring; never ask if the borrower RECEIVES alimony/child support (may ask what they PAY). Adverse-action notice within 30 days.\n\nFCRA / Reg V: credit needs permissible purpose + borrower authorization; adverse-action and risk-based-pricing notices; score disclosure. GLBA / Reg P protects nonpublic personal information (privacy + safeguard + pretexting rules). BSA/AML (FinCEN): SARs, source-of-funds verification, OFAC/Patriot Act ID checks. SAFE Act: MLO licensing, NMLS ID on docs. MAP Rule (Reg N) and UDAAP ban unfair, deceptive, or abusive acts — never call an ARM \"fixed,\" never bait-and-switch, never promise \"no cost.\" Mortgage fraud = any misstatement, misrepresentation, or omission a lender relies on (including occupancy fraud and straw buyers) — Penny never facilitates it. When unsure, hand off to a licensed human.";

export const KB_SECTIONS: KBSection[] = [{"id": "fha-loans", "title": "FHA Loans", "keywords": ["FHA", "government loan", "3.5 percent down", "low down payment", "first time buyer", "bad credit loan", "580 score", "MIP", "mortgage insurance premium", "HUD", "assumable", "gift for down payment", "fixer condition", "UFMIP", "streamline refinance"], "content": "FHA is a government-insured program under HUD. The lender is insured against loss on default, which is why FHA is more forgiving on credit and even accepts non-traditional or no-score files. A borrower can put as little as 3.5% down with a 580+ score, or 10% down with a 500-579 score. FHA carries two mortgage-insurance pieces: an Upfront Mortgage Insurance Premium (UFMIP, commonly financed into the loan) and an annual MIP paid monthly. If the starting loan-to-value is 90% or less, annual MIP drops after 11 years; above 90% LTV it generally lasts the life of the loan, so most FHA borrowers keep MIP until they refinance into a conventional loan once they have enough equity. FHA is owner-occupant only — move in within 60 days and occupy at least a year. Manual DTI guideline is roughly 31% front / 43% back, flexible with compensating factors, and there is no reserve requirement. Sellers may contribute up to 6%. FHA is assumable by a creditworthy buyer. FHA is stricter on property condition and will not insure a home needing safety/health repairs until they are completed. Borrowers must clear court-ordered judgments and cannot be in default on federal debt (checked via CAIVRS). An FHA Streamline refinances an existing FHA loan with reduced documentation, sometimes no appraisal, when the loan is current, produces a documented net tangible benefit, and returns no more than $500 cash. Penny explains eligibility but never quotes the borrower a rate or promises approval."}, {"id": "va-loans", "title": "VA Loans", "keywords": ["VA loan", "veteran", "military", "surviving spouse", "zero down", "no down payment", "funding fee", "certificate of eligibility", "COE", "residual income", "IRRRL", "VA streamline", "service connected disability", "100 percent financing", "entitlement"], "content": "VA loans serve eligible veterans and, in many cases, surviving spouses. They offer 0% down / 100% financing, require no monthly mortgage insurance, and are for a primary residence the borrower occupies within 60 days. The VA guarantees a portion of the loan to the lender (a guaranty, not insurance) — typically up to 25% of the loan value on default. The borrower needs a valid Certificate of Eligibility (COE), plus suitable credit and income. Instead of monthly MI, VA charges a one-time funding fee that varies by down payment, first vs. subsequent use, and transaction type; it is usually financed and is waived entirely for veterans with a 10%+ service-connected disability rating and for eligible surviving spouses. VA underwrites to the back-end (total) DTI only — roughly 41% for manual underwrites, higher through automated underwriting — and adds a residual-income test measuring the net income left after debts and shelter to cover living costs, with thresholds that vary by region and household size. VA caps lender origination at 1% and bars charging the veteran for attorney or escrow service fees. An appraisal produces a Notice of Value. The IRRRL (Interest Rate Reduction Refinance Loan) is the VA-to-VA streamline: usually no appraisal, no full credit package, no cash out. Waiting periods: 2 years after Chapter 7 or foreclosure/short sale, 1 year into a Chapter 13. Penny confirms eligibility basics and hands rate and term questions to a licensed human loan officer."}, {"id": "usda-loans", "title": "USDA Rural Loans", "keywords": ["USDA", "rural", "rural development", "zero down", "no down payment", "country home", "income limit", "guarantee fee", "502 guaranteed", "area median income", "direct loan", "eligible area"], "content": "USDA (U.S. Department of Agriculture) Guaranteed loans are for a primary residence in an eligible rural area. They offer 0% down / 100% financing and, through approved lenders, come only as 30-year fixed-rate loans. Two things must qualify: the property location (checked on USDA's eligibility map) and household income, which must be at or below 115% of the area median income. USDA charges an upfront guarantee fee (about 1% of the base loan, usually financed, which can push LTV above 100%) plus a small annual fee paid monthly — functioning like FHA MIP or conventional PMI to protect the lender. There is no down-payment or reserve requirement and no set minimum credit score, though many lenders look for 620 and no-score borrowers may qualify with alternate tradelines. Max DTI is roughly 29% front / 41% back for manual underwriting. Sellers may contribute up to 6%. USDA also runs a Direct Loan program for low- and very-low-income applicants, applied for through USDA directly. One timing note: USDA works from a fixed annual budget for guarantees and can exhaust it near the end of the federal fiscal year (September), suspending new guarantees until October — important for borrowers closing near that window. Waiting periods: 3 years after Chapter 7 or foreclosure/short sale, 1 year into a Chapter 13. Penny explains eligibility and directs pricing questions to a licensed human loan officer."}, {"id": "conventional-conforming-jumbo", "title": "Conventional, Conforming & Jumbo Loans", "keywords": ["conventional", "conforming", "jumbo", "Fannie Mae", "Freddie Mac", "conforming loan limit", "FHFA", "3 percent down", "620 score", "PMI", "non conforming", "high balance", "DU", "LPA", "automated underwriting", "GSE"], "content": "A conventional loan meets Fannie Mae / Freddie Mac guidelines and is not government-insured. A conforming loan is a conventional loan that stays within the FHFA loan limits, which reset every year (always confirm the current figure). A loan above those limits is non-conforming, and a jumbo is a conventional loan that exceeds the conforming limit — it cannot be sold to Fannie or Freddie, so it carries tighter credit, larger down payment, and higher reserve requirements. Conventional conforming loans allow as little as 3% down (97% LTV), require a 620 minimum qualifying score, and require private mortgage insurance (PMI) whenever the down payment is under 20% (LTV over 80%). Under the Homeowners Protection Act, PMI can be canceled by borrower request at 80% of original value and must automatically terminate at 78%. Back-end DTI can run up to about 50% through an automated underwriting system — Fannie's Desktop Underwriter (DU) or Freddie's Loan Product Advisor (LPA) — which also decides whether an appraisal waiver or reduced reserves apply; the 28/36 manual guideline is only a starting point. Derogatory waiting periods on conventional: 4 years after a Chapter 7 (2 with documented extenuating circumstances), 7 years after foreclosure, 4 years after a short sale. Conventional loans are generally not assumable. Penny describes structure and thresholds but never quotes an interest rate, APR, or payment and never promises approval."}, {"id": "dscr-investor-loans", "title": "DSCR & Investor Loans", "keywords": ["DSCR", "investor loan", "rental property", "investment property", "debt service coverage", "cash flow loan", "no income verification", "landlord loan", "LLC", "non owner occupied", "rental income qualifying", "1007 rent schedule", "portfolio loan"], "content": "A DSCR (Debt Service Coverage Ratio) loan is a Non-QM product for real-estate investors that qualifies the loan on the rental property's cash flow rather than the borrower's personal income and DTI. The ratio compares the property's rent to its full housing payment (principal, interest, taxes, insurance, and any HOA); a ratio of 1.0 means rent exactly covers the payment, and lenders typically look for a cushion above that. Because qualifying is property-based, DSCR loans usually skip personal tax returns, W-2s, and employment verification, which suits self-employed investors and those who write off income. They are for non-owner-occupied 1-4 unit and small residential investment properties, often allow closing in an LLC, and typically require a larger down payment and cash reserves than an owner-occupied loan, with pricing tied to credit score, LTV, and the coverage ratio. For a conventional loan using rental income instead, the appraisal adds a Single-Family Comparable Rent Schedule (Form 1007) and the underwriter generally uses 75% of the lease or comparable rent, building in a 25% vacancy factor; free-and-clear rental property must still be listed so its taxes, insurance, and HOA are counted. DSCR loans are not GSE or government products and do not carry a QM compliance presumption, but they follow legitimate underwriting standards. Penny explains how DSCR qualifying works and connects the investor to a licensed human loan officer for structure and pricing, never quoting a rate."}, {"id": "fix-flip-bridge", "title": "Fix-and-Flip, Bridge & Construction Loans", "keywords": ["fix and flip", "flip loan", "rehab loan", "hard money", "bridge loan", "construction loan", "construction to perm", "build a house", "short term loan", "renovation loan", "draw", "interest only", "after repair value", "ARV", "spec build"], "content": "These are short-term, business-purpose or transitional products. A fix-and-flip (rehab) loan funds the purchase and renovation of a property an investor intends to resell quickly; it is typically short-term and interest-only, often sized against the after-repair value, with renovation money released in draws as work is inspected and completed. A bridge loan is a short-term, usually interest-only loan secured by the borrower's current (for-sale) home, letting them tap that equity toward the down payment on a new home before the old one sells; it is repaid when the current home closes. A construction loan disburses money in a series of draws as the build progresses, with the borrower paying interest only on the amount drawn so far; when the home is finished it is paid off by a permanent 'take-out' or 'end' loan (fixed or adjustable). A construction-to-permanent loan combines both into one closing with a single set of costs, then recasts into a fully amortizing principal-and-interest loan once construction completes. Because many fix-and-flip and business-purpose loans are for commercial/investment purposes, they may fall outside consumer disclosure rules like TRID and the Ability-to-Repay rule, but they still follow the lender's own underwriting and any applicable state licensing. These products carry higher rates and short balloon-style payoffs, so exit strategy matters. Penny explains the structure and refers investors to a licensed human loan officer for terms."}, {"id": "bank-statement-non-qm", "title": "Bank-Statement & Non-QM Loans", "keywords": ["bank statement loan", "self employed loan", "non QM", "alternative documentation", "1099 loan", "P and L loan", "no tax returns", "asset depletion", "stated income alternative", "business owner loan", "non traditional income", "alt doc"], "content": "Non-QM (non-Qualified-Mortgage) loans are legitimate products for creditworthy borrowers whose income or profile doesn't fit agency rules — often the self-employed, gig workers, or investors. Unlike the risky pre-2008 stated-income/no-doc loans (which no longer exist), every Non-QM loan must still satisfy the Ability-to-Repay rule: the lender considers and verifies real income or assets, it simply uses alternative documentation. A bank-statement loan qualifies a self-employed borrower using 12-24 months of personal or business bank deposits to derive income, instead of tax returns that understate earnings after write-offs. Related Non-QM options include 1099-only loans, profit-and-loss statement loans, and asset-depletion (asset-utilization) loans that convert a large liquid asset balance into qualifying income. Non-QM loans do not meet the QM rule, are not bought by Fannie/Freddie or backed by a government program, and carry no QM compliance presumption, so they typically ask for stronger credit, larger down payments, and cash reserves, with pricing reflecting the added risk. They are a real solution for borrowers with imperfect credit or non-traditional income who can genuinely afford the payment — not a way around verification. Penny explains which documentation path fits a borrower's situation and refers them to a licensed human loan officer for a full review, without quoting a rate or promising approval."}, {"id": "arm-vs-fixed", "title": "Fixed-Rate vs. Adjustable-Rate (ARM) Loans", "keywords": ["ARM", "adjustable rate", "fixed rate", "5/1 ARM", "7/1", "hybrid ARM", "index", "margin", "fully indexed rate", "SOFR", "caps", "interest only", "rate adjustment", "start rate", "will my rate go up", "teaser rate"], "content": "Every mortgage is built on one of two rate structures. A fixed-rate loan keeps the same interest rate for the entire term (commonly 10, 15, 20, 25, or 30 years). Even then the total payment can move if escrowed taxes or insurance change or when mortgage insurance drops off — but the principal-and-interest portion never changes. An adjustable-rate mortgage (ARM) has a rate that periodically resets. The ARM rate equals an index (a public market rate that moves, today usually SOFR) plus a margin (the lender's fixed add-on, set at closing and never changed); together they form the fully indexed rate. An ARM starts at a lower 'start rate' that holds for an intro period, then adjusts. To protect the borrower, underwriters qualify ability to repay at the higher fully indexed rate, not the low start rate. In notation like 5/1 or 7/6, the first number is how many years the start rate holds and the second is how often it adjusts afterward (1 = yearly, 6 = every six months). ARMs limit movement with caps — a first-adjustment cap, a periodic cap, and a lifetime cap — plus a floor; the rate can never fall below the margin. It is a compliance violation to call any part of an ARM 'fixed.' An interest-only feature lets a borrower pay only interest for a set period, keeping the early payment lower without reducing the balance; interest-only and negative-amortization loans are not Qualified Mortgages. Penny explains the trade-offs plainly and never quotes a specific rate."}, {"id": "refinance-cashout-heloc", "title": "Refinance, Cash-Out, HELOC & Second Liens", "keywords": ["refinance", "refi", "cash out", "cash out refinance", "HELOC", "home equity line", "home equity loan", "second mortgage", "tap equity", "pay off debt", "lower my payment", "tangible net benefit", "subordination", "draw period", "piggyback"], "content": "A refinance replaces an existing mortgage with a new one. On any refinance the underwriter must confirm a tangible net benefit — a real advantage that outweighs the cost, such as a lower rate or payment, a shorter term, moving from an ARM to fixed, dropping mortgage insurance, consolidating liens, ending negative amortization, or a reasonable cash-out — a rule that exists to prevent 'churning' borrowers for fees. A cash-out refinance borrows against equity and returns funds to the borrower; to estimate proceeds: value times the allowed LTV, minus the existing payoff and any financed costs, with a positive remainder brought to close and a negative remainder paid out as cash. A HELOC (home equity line of credit) is a revolving, open-end second loan: the borrower draws, repays, and re-draws during a draw period (commonly 5, 10, or 15 years), usually interest-only during the draw, up to roughly 80% of equity, and it is generally adjustable (tied to Prime). A closed-end home equity loan pays one lump sum at closing and can be fixed or adjustable. A 'simultaneous second' or piggyback closes alongside the first mortgage, often to avoid PMI. A refinance of a PRIMARY residence carries a 3-business-day right of rescission — the borrower can cancel and the loan cannot fund until that window passes — but this does not apply to purchases, second homes, or investment properties. HELOCs use a separate CFPB booklet. Penny explains options without quoting rates or promising approval."}, {"id": "credit-scores-qualifying", "title": "Credit, Scores & Derogatory Seasoning", "keywords": ["credit score", "FICO", "tri merge", "middle score", "620", "payment history", "collections", "charge off", "late payment", "bankruptcy", "foreclosure", "short sale", "waiting period", "seasoning", "credit pull", "representative score", "how good does my credit need to be"], "content": "Lenders pull a tri-merge report from all three bureaus — Experian, Equifax, TransUnion. For one borrower the underwriter uses the middle of the three scores; with two or more borrowers, the lowest middle score becomes the qualifying 'representative' score that drives pricing. Scores run 300-850 and are built from payment history (35%), amounts owed / utilization (30%), length of history (15%), credit mix (10%), and inquiries (10%). Minimum scores vary by program: conventional generally 620, FHA 580 for 3.5% down (500-579 with 10% down), USDA/VA no hard minimum though lenders often want 620. Mortgage lates in the last 12 months hurt most — a conventional file showing a 60-day mortgage late in the past year is generally denied absent extenuating circumstances. Collections and charge-offs damage the score but don't automatically block a loan; guidelines decide whether they must be paid. Ideally a borrower pays off derogatory accounts before credit is pulled so the score has time to update. Derogatory waiting periods by program — conventional: 4 years Chapter 7, 7 years foreclosure, 4 years short sale; FHA: 2 years Chapter 7, 3 years foreclosure/short sale; VA: 2 years Chapter 7 or foreclosure/short sale; USDA: 3 years Chapter 7 or foreclosure/short sale (Chapter 13 waits are shorter, often starting after ~12 months of on-time plan payments). Inquiries mostly matter for the last 6 months, and rate-shopping in a short window is treated as reduced impact. Borrowers should not open new credit during the process — it can be re-pulled before closing. Penny coaches gently and never guarantees a score outcome or approval."}, {"id": "income-documentation", "title": "Income Documentation & Self-Employment", "keywords": ["income", "proof of income", "W2", "pay stub", "tax returns", "2 year history", "self employed", "1099", "commission", "bonus", "overtime", "VOE", "verification of employment", "gross up", "rental income", "stable vs variable", "AGI", "how do you calculate my income"], "content": "Borrowers generally show a 2-year income history, ideally the same employer or line of work. Income is verified with W-2s, pay stubs, 1099s, and/or tax returns (paired with a signed 4506-C that lets the lender confirm figures match IRS records), plus a Verification of Employment. Income not claimed on a tax return cannot be used. Income is either stable (base salary, consistent hourly, Social Security, retirement, long-term disability — used as-is) or variable (commission, bonus, overtime, second job, self-employment — averaged over 2 years); if variable income is declining but stabilized, the underwriter uses the lower figure. Commission over 25% of pay requires 2 years of tax returns. Income with an expiration date (alimony, child support, some Social Security, trust, VA benefits) must be shown to continue at least 3 years. Nontaxable income (Social Security, some public assistance) may be 'grossed up' 25% (15% on FHA) once verified as nontaxable. Monthly conversions: annual ÷ 12; bi-weekly x 26 ÷ 12; weekly x 52 ÷ 12; semi-monthly x 2; hourly x avg weekly hours x 52 ÷ 12 (2,080 hours = full-time year); overtime hours at time-and-a-half. A borrower owning 25%+ of a business is self-employed, needs both personal and business returns, is analyzed on net income / AGI (adding back non-cash items like depreciation), and typically needs a 2-year history. Penny explains what documents are needed and lets the underwriter make the income determination."}, {"id": "dti-ratios", "title": "Debt-to-Income (DTI) Ratios", "keywords": ["DTI", "debt to income", "front end", "back end", "housing ratio", "total debt ratio", "how much debt can I have", "monthly payments", "qualify", "student loan payment", "car loan", "credit card", "PITI", "43 percent", "50 percent", "too much debt"], "content": "DTI compares monthly obligations to gross monthly income and is the heart of Capacity. The front-end (housing) ratio is the full housing payment — PITI plus HOA, any second lien, and mortgage insurance — divided by gross monthly income. The back-end (total) ratio adds all other monthly debts and is usually the binding number. Rough program guidelines: conventional up to about 50% through automated underwriting (45% manual with strong credit and reserves), FHA ~31/43 (flexible with compensating factors), VA 41% back-end plus the residual-income test, USDA ~29/41 manual. Counted debts include the housing payment, all revolving/credit-card minimums, installment loans with more than 10 months left, ALL lease payments regardless of months remaining, other property mortgages, HELOCs, alimony, child support, and maintenance. NOT counted: utilities, cell phone, personal insurance, taxes, union dues, daycare, and voluntary paystub deductions like 401(k) contributions or 401(k) loans (the borrower's own money). An installment loan with 10 or fewer payments left can be excluded — except a leased vehicle, which always counts. When no student-loan payment shows, roughly 0.5-1% of the balance may be used; for a revolving account with no listed payment, 5% of the balance is generally accepted. Borrowers must disclose debts even if they don't appear on the report — omitting one is an Ability-to-Repay violation. Opening new credit mid-process forces a DTI recalculation and can disqualify a marginal file. Penny estimates conceptually but the underwriter runs the final numbers."}, {"id": "down-payment-assets-reserves-gifts-dpa", "title": "Down Payment, LTV, Assets, Reserves, Gifts & Assistance", "keywords": ["down payment", "how much down", "LTV", "loan to value", "assets", "reserves", "savings", "gift funds", "gift letter", "down payment assistance", "DPA", "seasoning", "60 days", "sourced funds", "401k", "cash to close", "seller concessions", "first time buyer help", "closing costs help"], "content": "Loan-to-value (LTV) = the loan amount divided by the LESSER of purchase price or appraised value — money paid above appraised value does not reduce LTV. Combined LTV (CLTV/TLTV) adds a second lien; high-CLTV counts the entire HELOC line. Minimum down payment by program: conventional as low as 3%, FHA 3.5%, VA and USDA 0%. Assets for down payment and closing must be sourced and generally 'seasoned' 60 days in the borrower's account, verified by bank statements or a Verification of Deposit; undocumented cash is not allowed. Sources that only need sourcing (not 60 days) include gifts, inheritances, insurance payouts, and lawsuit awards. Gift funds are allowed with no expectation of repayment, usually from a family member, significant other, or employer, and always documented with a gift letter naming the donor, relationship, amount, and that no repayment is required; on FHA a gift can cover the entire down payment. Down-payment assistance runs through state, county, or city programs, often (not always) for first-time buyers. A borrower may borrow against a secured asset (car, 401(k)) — any new payment is added to DTI, except a 401(k) loan/withdrawal, which is not. Reserves are liquid funds left after closing, measured in months of PITI, and can include vested retirement; second homes and investment properties generally require them. Seller (interested-party) contributions are capped by program and LTV (FHA 6%; conventional 3-9% by LTV; investment 2%). Penny explains sources and documentation clearly; fair lending means the same standards apply to every borrower."}, {"id": "pmi-mip", "title": "Mortgage Insurance: PMI, MIP, Funding & Guarantee Fees", "keywords": ["PMI", "private mortgage insurance", "MIP", "mortgage insurance", "when does PMI go away", "20 percent equity", "funding fee", "guarantee fee", "UFMIP", "remove mortgage insurance", "78 percent", "80 percent", "monthly insurance", "get rid of PMI"], "content": "Mortgage insurance protects the LENDER, not the borrower, whenever there's a smaller down payment. Conventional loans use private mortgage insurance (PMI) from a third-party insurer when LTV exceeds 80%. Under the Homeowners Protection Act the borrower can REQUEST PMI cancellation once the balance reaches 80% of original value (20% equity), and the servicer must AUTOMATICALLY terminate it at 78%. FHA uses its own two-part mortgage insurance premium: an Upfront MIP (UFMIP, financed) plus an annual MIP paid monthly; if the starting LTV is 90% or less, annual MIP ends after 11 years, but above 90% it typically lasts the life of the loan — so most FHA borrowers eliminate it only by refinancing into a conventional loan once they have enough equity. The FHA annual MIP dollar amount drops slightly each year as the balance falls, recalculated annually. The government-program equivalents of PMI are the FHA UFMIP/MIP, the VA one-time Funding Fee (waived for a 10%+ service-connected disability and eligible surviving spouses; no monthly MI on VA), and the USDA upfront + annual Guarantee Fee. Each of these upfront amounts can be financed on top of the base loan. Mortgage insurance is included in APR and Ability-to-Repay calculations. Penny explains what type of MI a loan carries and how it comes off, but never quotes the specific premium as part of a rate or payment promise."}, {"id": "appraisal", "title": "The Appraisal", "keywords": ["appraisal", "appraiser", "home value", "market value", "comps", "comparable sales", "AMC", "appraisal came in low", "USPAP", "appraisal waiver", "PIW", "who orders the appraisal", "independence", "appraisal fee", "1004"], "content": "An appraisal is an independent, supportable opinion of a property's market value, delivered in a written report. It sets the value used for LTV and confirms the collateral securing the loan. Appraisers are state-licensed, follow USPAP (Uniform Standards of Professional Appraisal Practice), and may need extra certification for FHA or VA work. Appraiser independence is the law: no one in the transaction — including the loan officer — may contact the appraiser directly or pressure, coerce, bribe, or influence the value, and payment cannot be withheld because a value came in low. Appraisals are ordered through a neutral Appraisal Management Company (AMC), which relays any questions or corrections. The most common method is the Sales Comparison Approach, requiring at least three comparable sales (usually within a mile and under six months old, with explanation if further), where adjustments are applied to the comparable, not the subject. The Cost Approach (land plus replacement cost minus depreciation) and Income Approach (for rentals/multi-unit) are also used. Some loans qualify for an appraisal waiver — Fannie's Property Inspection Waiver or Freddie's ACE — revealed by the automated underwriting findings. Under the ECOA Valuations Rule the borrower is told within 3 business days of application of their right to a copy of the appraisal and must receive it promptly, at least 3 business days before closing, even if the loan doesn't close (within 30 days if it's cancelled). If a low appraisal comes in, Penny cannot 'bump the number' — she explains options like renegotiating price, disputing with new comps through the AMC, or bringing more cash."}, {"id": "title-escrow-insurance", "title": "Title, Escrow, Homeowners & Flood Insurance", "keywords": ["title", "title insurance", "title search", "escrow account", "impound", "closing costs", "homeowners insurance", "hazard insurance", "flood insurance", "loss payee", "mortgagee clause", "lien", "deed", "owner's policy", "lender's policy", "escrow analysis", "force placed insurance"], "content": "Title is the bundle of a borrower's legal rights to the property. A title company runs a title search producing a report showing the chain of ownership, easements, restrictions, tax assessments, and any liens or obstructions. Title insurance protects against future loss if those rights are challenged (forged deeds, missing heirs, recording errors, fraud): the owner's policy protects the buyer (optional but recommended, covering the purchase price) and the lender's policy protects the lender (at least the loan amount, reissued each refinance) — a one-time premium paid at closing. Liens generally pay in the order they attached, except property-tax liens, which come first; a subordination agreement keeps an existing second in second position during a refinance. An escrow/impound account collects 1/12 of annual property taxes and homeowners insurance with each payment so the servicer pays those bills; RESPA caps the cushion at 2 months, requires an annual analysis, and refunds surpluses of $50+. On an HPML, escrows are mandatory for at least 5 years. Homeowners (hazard) insurance is required to close, must at minimum equal the replacement cost of the structure (a lender cannot require more than insurable value), and the borrower picks the company; the lender is named as loss payee (mortgagee clause). If a borrower lets it lapse, the servicer can 'force-place' more expensive coverage. Every file needs a flood determination; when the property sits in a Special Flood Hazard Area (zone A or V), flood insurance is required — flood policies cover only rising water, while wind/rain damage falls under homeowners. Penny is not an insurance agent and refers coverage questions to a licensed agent."}, {"id": "loan-process-underwriting-closing", "title": "Loan Process, Underwriting, Closing & Pre-Approval", "keywords": ["process", "timeline", "how long does it take", "underwriting", "conditions", "conditional approval", "clear to close", "closing", "funding", "consummation", "pre approval", "pre qualification", "pre qual", "3 day rule", "closing disclosure", "right of rescission", "what happens next", "steps"], "content": "The path: an application exists once the 6 ALIENS items are collected — property Address, Loan amount, Income, Estimated value, Name, and SSN. That triggers the Loan Estimate, which must be delivered within 3 business days. The borrower then gives Intent to Proceed (silence never counts); only after that can the lender charge fees beyond a reasonable credit-report fee. Next comes processing, ordering the appraisal, and underwriting — where the underwriter (never Penny) independently reviews the file against program guidelines and makes the final approve/deny decision. Approval usually comes 'conditional,' with a list of conditions (updated pay stub, letter of explanation, verification of funds, appraisal items) that must be satisfied to reach 'clear to close.' Then the Closing Disclosure (the final numbers) must be received at least 3 business days before consummation. At closing the borrower signs the promissory note (the debt) and the security instrument (mortgage or deed of trust). Consummation is the moment the borrower is contractually obligated; funding is when money disburses. A refinance of a primary residence adds a 3-business-day right of rescission before funds release. Pre-qualification is a quick, informal estimate based on stated information — a starting conversation. Pre-approval is stronger: the borrower submits documentation and credit is pulled, so the lender can issue a conditional commitment that sellers take seriously — but neither is a guaranteed final approval, which only the underwriter gives. Penny keeps the borrower moving, sets honest expectations on timing, and never promises approval or a specific rate."}, {"id": "disclosures-le-cd-trid", "title": "Loan Estimate, Closing Disclosure & the TRID Timeline", "keywords": ["loan estimate", "LE", "closing disclosure", "CD", "paperwork", "disclosures", "when do I get my paperwork", "how fast can we close", "three day rule", "3 day wait", "closing timeline", "review period", "forms", "estimate of costs", "good faith estimate", "HUD-1", "intent to proceed", "application complete", "final numbers"], "content": "TRID (the TILA-RESPA Integrated Disclosure rule, effective 2015) governs the two forms borrowers see. The Loan Estimate (LE) replaced the old Good Faith Estimate and early Truth-in-Lending; the Closing Disclosure (CD) replaced the HUD-1. The LE must be delivered within 3 business days after a complete application — which is just six items (ALIENS: property Address, Loan amount, Income, Estimate of value, Name, Social Security number). The initial CD must be received at least 3 business days before consummation so the borrower has real time to review final numbers; for CD timing, Saturdays count but Sundays and federal holidays don't. A loan can't close sooner than 7 business days after the LE goes out, and any revised/final LE must arrive at least 4 business days before closing, at least one day before the initial CD (they can't go out the same day). A lender may not charge any fee — except a bona-fide credit-report fee — or require verifying documents before the borrower sees the LE and states intent to proceed. The initial LE quote holds for 10 business days. Only three late changes reset a fresh 3-day CD wait: the loan program changes, a prepayment penalty is added, or the APR moves out of tolerance (more than 1/8% on a fixed loan, 1/4% on an ARM). Signing either form only confirms receipt, never acceptance. Penny explains timing and purpose but never quotes the borrower's actual costs."}, {"id": "tila-regz-apr", "title": "Truth in Lending (Reg Z) and How APR Works", "keywords": ["truth in lending", "TILA", "regulation Z", "reg z", "APR", "annual percentage rate", "interest rate vs APR", "why is APR higher", "finance charge", "cost of credit", "all in cost", "what does APR mean", "points", "total cost", "note rate"], "content": "The Truth in Lending Act (TILA, 1968), implemented by Regulation Z and enforced by the CFPB, is the oldest mortgage consumer law still in force. Its job is transparency so borrowers can compare the true cost of credit. It applies to consumer credit on 1-4 unit properties for personal/family/household use, not business, commercial, or agricultural loans. The note interest rate is the figure the monthly principal-and-interest payment is built from. The APR is broader: it folds the interest together with lender- and rate-related 'finance charges' — origination, processing, underwriting, discount points, prepaid interest, the lender's title policy, and mortgage insurance — and expresses the whole cost as one annual rate. Because it adds those costs, the APR is normally higher than the note rate; it's a comparison and risk indicator, not the payment figure. Costs that aren't about the loan itself (property taxes, homeowner's insurance, owner's title policy, recording fees, most notary and attorney fees) generally stay out of the APR. Because fixed-dollar closing costs are a larger slice of a smaller loan, APR can look higher on a smaller loan at the same note rate. Under the TILA umbrella sit HOEPA, HPML, QM, ATR, LO Compensation, advertising rules, the CHARM booklet, the right of rescission, and TRID. Records are kept at least 2 years (LO-comp and ATR records 3 years, the CD 5 years). Penny explains the APR concept but always points the borrower to their disclosures and a licensed officer for actual figures."}, {"id": "respa-regx", "title": "RESPA (Reg X): Kickbacks, Escrow & Settlement Costs", "keywords": ["RESPA", "regulation X", "settlement costs", "closing costs", "escrow account", "impound", "kickback", "referral fee", "affiliated business", "AfBA", "escrow refund", "escrow surplus", "section 8", "title insurance choice", "home loan toolkit", "surplus check"], "content": "The Real Estate Settlement Procedures Act (RESPA, 1974, Regulation X) is specific to real estate. It educates borrowers on settlement costs, eliminates kickbacks and referral fees, and limits escrow deposits. It covers 1-4 family dwellings, condos, and manufactured homes on federally related loans, but not vacant land, tracts of 25+ acres, commercial/business loans, government entities, or temporary bridge financing. Section 8 prohibits giving or receiving any fee, kickback, or 'thing of value' for referrals, or splitting charges for services not performed — penalties include fines, up to a year in prison, and treble damages. An Affiliated Business Arrangement (AfBA) — where a referrer has an affiliate relationship or more than 1% ownership in a settlement provider — must be disclosed at the time of referral. Section 9 bars a seller from forcing the buyer to use a particular title company. On escrows, the lender may hold only enough to pay the bills plus a cushion of up to 2 months (1/6 of annual taxes/insurance). An annual escrow analysis is required; a surplus of $50 or more must be refunded — that's why a borrower sometimes gets a surplus check, which is the account balancing, not a mistake. The Home Loan Toolkit (purchases) and a homeownership-counselor list are provided within 3 business days of application. Penny reassures borrowers about these protections without quoting fee amounts."}, {"id": "ecoa-regb-fair-lending", "title": "ECOA, Reg B & Fair Lending", "keywords": ["fair lending", "discrimination", "ECOA", "equal credit opportunity", "regulation B", "protected class", "public assistance", "food stamps", "welfare", "single parent", "marital status", "child support", "alimony", "age discrimination", "denied for", "adverse action", "equal housing", "can I even apply", "fair housing", "disability"], "content": "The Equal Credit Opportunity Act (ECOA, 1974, Regulation B, CFPB-enforced) makes it unlawful to discriminate in any part of a credit transaction based on race, color, religion, national origin, sex (including sexual orientation), marital status, age, income from a public-assistance program, or exercising a Consumer Credit Protection Act right. Everyone creditworthy must be allowed to apply — being allowed to apply is not a promise of approval. Fetti is an Equal Housing Opportunity lender. A loan officer cannot request race, color, religion, national origin, or sex except for HMDA government monitoring. Only 'married,' 'unmarried,' or 'separated' may be recorded. A lender cannot ask whether an applicant RECEIVES alimony or child support (the applicant may volunteer it to help qualify) but must ask what they PAY, because that's a liability. A lender cannot use childbearing assumptions, consider a phone listing in the applicant's name, discount part-time income, or deny for receiving public assistance or being a single parent. Age may be a denial basis only when the applicant is too young to contract. Any decision must be communicated within 30 days; adverse-action notices state specific principal reasons. The ECOA Valuations Rule requires giving the borrower a copy of every appraisal promptly and at least 3 business days before consummation. The Fair Housing Act (1968, amended 1988) covers the same ground, adds disability, and reaches appraisers, agents, and title companies. Penny treats every caller equally and never discourages anyone."}, {"id": "hmda", "title": "HMDA (Reg C) — Lending Data & Anti-Redlining", "keywords": ["HMDA", "home mortgage disclosure", "regulation C", "redlining", "lending data", "reporting", "why do you ask my race", "government monitoring", "demographic information", "preferred language", "fair lending data", "discrimination patterns"], "content": "The Home Mortgage Disclosure Act (HMDA, 1975, Regulation C, CFPB-enforced) requires covered lenders to report loan-level data so regulators can see whether institutions serve their communities and can spot discriminatory patterns like redlining, reverse redlining, blockbusting, disparate treatment, and disparate impact. Coverage generally applies to institutions that originated at least 25 closed-end mortgages or at least 200 open-end lines of credit in each of the two prior years. This is the one situation where an applicant is asked about race, ethnicity, and sex — purely for government monitoring, never to decide the loan; applicants may decline to answer. Mortgage brokers typically don't file HMDA because they don't make the underwriting decision or close in their own name; the wholesale lender that underwrites and funds files the report, which captures both the company and the individual originator's NMLS numbers. Preferred language is gathered on the Supplemental Consumer Information Form (SCIF, Form 1103); the originator must make every effort to serve the borrower in that language and cannot charge for translation. The full data set runs to dozens of fields; the report is due to the regulator by March 1, the modified public LAR by March 31, and records are kept at least 3 years (the disclosure statement 5). The public file strips loan numbers and dates to protect privacy. Penny explains that demographic questions are monitoring-only and never affect the decision."}, {"id": "fcra-credit", "title": "FCRA / FACTA — Credit Reports & Your Rights", "keywords": ["credit report", "credit score", "FCRA", "fair credit reporting", "pull my credit", "permissible purpose", "adverse action", "denied because of credit", "free credit report", "dispute", "rescore", "rapid rescore", "risk based pricing", "notice to home loan applicant", "negative items", "how long stays on report", "credit freeze", "fraud alert"], "content": "The Fair Credit Reporting Act (FCRA, 1970, Regulation V) governs how credit information is used. Credit can only be pulled with the borrower's authorization and a permissible purpose — a loan application the consumer initiated, not curiosity or a friend. Most negative information drops off after 7 years; bankruptcies can stay up to 10. If a loan is denied wholly or partly because of credit-report information, the borrower must get an FCRA adverse-action notice within 30 days that names the bureau used, states the bureau didn't make the decision, and explains the borrower's right to a free copy of that report; a common violation is omitting the credit score when a score was used. FCRA prohibits charging the borrower a fee for a rapid rescore. FACTA (2003) added one free annual report per bureau via annualcreditreport.com, the Notice to Home Loan Applicant (score used, score range, up to four key factors, date, bureau), the risk-based-pricing notice when a borrower gets materially less favorable terms because of credit, the Red Flags Rule and Disposal Rule for identity-theft prevention, extended fraud alerts to one year, and made credit freezes free (placed within one business day, lifted within an hour online). When a creditor reports negative information, it must notify the consumer within 30 days, and disputes must be resolved within 30 days. Penny may explain these rights and encourage borrowers to review their reports, but never repairs credit without a license and never quotes score-based pricing."}, {"id": "right-to-shop", "title": "Your Right to Shop & Intent to Proceed", "keywords": ["shop around", "compare offers", "other lenders", "right to shop", "intent to proceed", "do I have to commit", "am I locked in", "upfront fees", "application fee", "can I get other quotes", "service provider list", "choose my own provider", "no obligation"], "content": "Borrowers have a protected right to shop. The Loan Estimate is a standardized form precisely so a borrower can lay Fetti's offer next to another lender's and compare apples-to-apples — the APR line and the Total Interest Percentage help with that. Signing the LE only confirms receipt; it never obligates the borrower to take the loan. A lender cannot charge any fee beyond a bona-fide credit-report fee, and cannot require documents verifying application information, until the borrower has seen the LE and affirmatively communicated 'intent to proceed' (verbally or in writing — silence never counts, and it must be documented). Under TRID, the lender must give a written list of settlement-service providers (the SSPL) with at least one provider for each service the borrower is allowed to shop for. Fees for services the borrower shops on their own carry no tolerance (they can change), while services chosen off the lender's written list stay within a 10% cumulative tolerance; zero-tolerance fees like origination can't increase at all. RESPA Section 9 also protects the buyer from being forced to use a particular title company. Penny actively reassures borrowers that getting other quotes is smart and expected, that there's no obligation until closing documents are signed, and that no meaningful fee is owed just for getting started."}, {"id": "right-of-rescission", "title": "Right of Rescission — The 3-Day Cancel Window", "keywords": ["cancel", "right of rescission", "change my mind", "back out", "three day cancel", "rescind", "refinance cancel", "cooling off", "primary residence refi", "can my spouse cancel", "cancel after signing", "rescission notice", "void the loan"], "content": "The right of rescission is a TILA/Reg Z protection giving the borrower 3 business days to cancel AFTER signing — but only on a refinance or home-equity loan secured by the borrower's PRIMARY residence. It does NOT apply to purchase loans (those fund without a rescission period), and it does NOT apply to second/vacation homes or investment/business-purpose loans even when owner-occupied. Saturdays count toward the three days; Sundays and legal holidays don't. The window runs from the latest of signing, delivery of the rescission notice, or delivery of all required disclosures. The borrower must receive two copies of the notice of the right to rescind plus one copy of the disclosure statement; the notice is a separate document identifying the deadline, the retained security interest in the home, and how to exercise the right. Any single person holding an ownership interest in the home may rescind — even someone not on the loan — and if one person cancels, the transaction is void for everyone. After a valid cancellation, the creditor must unwind the deal and return money or property within 20 calendar days and refund the appraisal cost; cancelling before closing triggers no refund. If the notice was never provided or disclosures contained errors, the right extends to 3 years. A borrower may waive it only for a bona-fide personal financial emergency, via a dated, handwritten, signed statement. Penny confirms which situation applies to each caller."}, {"id": "hoepa-hpml-highcost", "title": "High-Cost (HOEPA §32) & Higher-Priced (HPML §35) Loans", "keywords": ["high cost loan", "HOEPA", "section 32", "HPML", "higher priced", "section 35", "predatory", "APOR", "escrow required", "extra appraisal", "prepayment penalty", "points and fees", "balloon", "expensive loan protections", "special disclosure"], "content": "Loans are classified by how far their APR sits above the Average Prime Offer Rate (APOR) — the rate the best-credit borrowers nationwide receive, published weekly by the FFIEC and measured on the lock date. A Higher-Priced Mortgage Loan (HPML, TILA §35) is a first lien whose APR exceeds APOR by more than 1.5 points (2.5 above FHFA limits; 3.5 for a subordinate lien). HPMLs aren't predatory but carry extra protections: a written appraisal with a borrower copy (plus a second appraisal on quick flips, not charged to the borrower), an escrow account for at least 5 years regardless of LTV, no prepayment penalty on an ARM, and full ability-to-repay verification. A High-Cost mortgage (HOEPA §32, a 1994 TILA amendment) is flagged if it fails just ONE of three tests: the APR test (first-lien APR more than 6.5 points over APOR for loans of $50,000+), the points-and-fees test (roughly 5% of the loan amount), or the prepayment-penalty test (a penalty chargeable beyond 36 months or exceeding 2% of the amount prepaid). High-cost loans require pre-loan homeownership counseling with a completion certificate, a special disclosure at least 3 business days before closing, and they ban balloons, most prepayment penalties, and due-on-demand clauses; points and fees can't be financed. Reverse, construction, USDA §502 Direct, and housing-finance-agency loans are exempt from HOEPA. Penny explains these are borrower-protection categories, never price quotes, and defers pricing to a licensed officer."}, {"id": "glba-privacy", "title": "GLBA (Reg P) — Privacy & Your Personal Information", "keywords": ["privacy", "GLBA", "gramm leach bliley", "regulation P", "personal information", "NPI", "data protection", "privacy notice", "opt out", "do you sell my information", "safeguard", "pretexting", "identity protection", "is my data safe"], "content": "The Gramm-Leach-Bliley Act (GLBA, 1999, Regulation P) protects a borrower's nonpublic personal information (NPI) — data not available in public records, such as Social Security numbers, bank and loan account numbers, and credit card numbers (name, address, and phone are public and not NPI). NPI must be protected from the first contact, throughout the loan, and afterward as long as the firm holds it. GLBA has three rules: the Safeguard Rule (a written information-security plan sized to the firm), the Financial Privacy Rule (privacy notices plus opt-out rights), and the Pretexting Rule (a crime to obtain someone's financial information under false pretenses by impersonation). There are four privacy notices: an Initial notice when the relationship begins, an Opt-Out notice before sharing NPI with non-affiliated third parties, an Annual notice for the life of a customer relationship, and a Revised notice if the policy changes. A borrower can opt out of having NPI shared or sold to non-affiliated third parties; sharing information with the parties actually needed to complete the loan is allowed and isn't what opt-out covers — and many lenders simply don't sell information at all. Related identity-theft safeguards include FACTA's Red Flags Rule (spotting suspicious documents and inconsistent identifying information) and the Disposal Rule (shredding or destroying records). Penny reassures borrowers their information is protected and never asks for sensitive data over insecure channels."}, {"id": "bsa-aml", "title": "BSA/AML, Patriot Act & Source of Funds", "keywords": ["money laundering", "BSA", "anti money laundering", "AML", "FinCEN", "suspicious activity", "SAR", "patriot act", "OFAC", "source of funds", "large cash", "seasoning", "where did the money come from", "identity verification", "two forms of ID"], "content": "The Bank Secrecy Act / Anti-Money-Laundering framework (1970, enforced by FinCEN) exists to detect and prevent money laundering — disguising criminally obtained money as legitimate. Institutions must run a compliance program: risk assessment, internal controls, a designated AML compliance officer, annual training (loan officers included), independent testing, and customer due diligence. Suspicious Activity Reports (SARs) are filed with FinCEN no later than 30 days after detection and retained 5 years; triggers include insider abuse of any amount, transactions of $5,000+ with an identifiable suspect, $25,000+ regardless of suspect, and $5,000+ tied to potential money laundering. Because home purchases have been used to launder money, lenders must source and verify all funds; large cash brought to closing is a red flag unless documented, and most funds need roughly 60 days of seasoning (a paper trail). The USA Patriot Act (2001, FinCEN/Treasury) requires a Customer Identification Program: collect the borrower's name, date of birth, and an ID number (SSN/TIN for U.S. persons; passport or alien ID for non-citizens), typically checking two forms of ID and keeping a Patriot Act disclosure. Borrowers are screened against the OFAC list of known or suspected terrorists. Penny never coaches a borrower on how to move undocumented money and always asks for a clear paper trail; anything that looks like structuring or hidden funds is escalated to a human, and if warranted a SAR is filed."}, {"id": "safe-nmls-licensing", "title": "SAFE Act & NMLS Licensing", "keywords": ["licensed", "NMLS", "SAFE act", "are you licensed", "license number", "verify your license", "registered", "loan officer license", "NMLS consumer access", "who am I working with", "background check", "unique identifier"], "content": "The SAFE Act (Secure and Fair Enforcement for Mortgage Licensing Act, 2008, part of HERA) set nationwide minimum standards for mortgage loan originators after the 2008 crisis; before it, not every state required licensing. Loan officers at independent (non-bank) mortgage companies must be individually state-licensed — pre-licensing education, a national exam, fingerprints, a criminal background check, and a credit review — while originators inside a bank or credit union are federally registered instead. Every licensed loan officer and company has a unique NMLS identifier that must appear on the loan application, certain disclosures, and all advertising. Borrowers can verify any originator and company for free on the NMLS Consumer Access website; Fetti Financial Services' NMLS number is 2267023. An individual must be licensed or registered to perform loan-originator activity and to be compensated for it. Felonies involving fraud, dishonesty, breach of trust, or money laundering screen a person out of the industry. Regulators can suspend or revoke a license and fine violators — the SAFE Act's statutory maximum is up to $25,000 per violation (inflation-adjusted higher), with each act counted separately. Licensed companies also carry a surety bond so borrowers financially harmed by misconduct can recover, similar to malpractice coverage. Penny always encourages borrowers to verify the license on NMLS Consumer Access and identifies that she is an AI assistant, with a licensed human loan officer handling anything requiring a license."}, {"id": "map-advertising-rule", "title": "MAP Rule (Reg N) — Honest Advertising", "keywords": ["advertising", "MAP rule", "regulation N", "bait and switch", "misleading ad", "no cost loan", "zero down", "preapproved letter", "false claim", "best rate guarantee", "government affiliation", "deceptive advertising", "trigger terms", "APR in ad"], "content": "The Mortgage Acts and Practices Rule (MAP Rule, Regulation N, 2009, FTC-enforced) bans any material misrepresentation about any mortgage term in advertising or other commercial communication — misleading claims about rates, fees, payments, prepayment penalties, government affiliation, or whether someone is 'preapproved.' Covered communications must be kept at least 2 years. Under TILA's advertising rules, an ad is anything produced to sell a credit plan (print, radio, TV, signs, websites, social media); internal rate sheets and purely educational material are not ads. When advertising to borrowers, a lender must advertise only terms it will actually offer, state any finance-charge rate as 'Annual Percentage Rate' or 'APR,' show the APR at least as conspicuously as any simple rate, and disclose if the APR can increase. A 'trigger term' — a specific down-payment amount, a percentage of financing, or a specific payment — forces additional disclosures (price, down payment, number and amount of payments, and the APR). General phrases like 'low down payments' or 'financing available' don't trigger those disclosures. ARM ads must state the rate can change, and a lender can't hide friendlier plans to bait-and-switch. If a borrower asks about a plan's cost, the APR must be disclosed and stated first. Penny never advertises terms Fetti can't deliver, never says 'no cost' or 'guaranteed lowest,' and never quotes specific numbers — she describes how the process works and hands pricing to a licensed officer."}, {"id": "udaap-ethics", "title": "UDAAP, Ethics & Consumer Protection", "keywords": ["UDAAP", "unfair", "deceptive", "abusive", "ethics", "predatory lending", "steering", "taking advantage", "fine print", "dark patterns", "misleading", "consumer protection", "is this a scam", "are you being straight with me", "fair treatment"], "content": "UDAAP — the Dodd-Frank prohibition on Unfair, Deceptive, and Abusive Acts or Practices, enforced by the CFPB — is the ethical backstop over everything Penny does. 'Unfair' means causing substantial injury a consumer can't reasonably avoid and that isn't outweighed by benefits. 'Deceptive' means likely to mislead a reasonable consumer on something material, including by omission — calling an ARM 'fixed,' misstating the APR, saying 'no cost' or 'zero down' when real costs exist, or bait-and-switch. 'Abusive' means interfering with a consumer's understanding of a term, or taking unreasonable advantage of their lack of understanding, inability to protect themselves, or reasonable reliance on the originator — and abusive doesn't require proving intent. Per CFPB guidance, violating almost any mortgage rule is also a UDAAP violation because the borrower relies on the loan officer and often can't protect themselves, and one act can break several laws at once. Discrimination itself is treated as abusive, so outreach must reach all markets and never deselect a group (which can be redlining if geographic). 'Materially interferes' can be shown through fine print, jargon, buried or badly timed disclosures, or digital dark patterns. Steering a borrower or self-dealing when they rely on you for guidance is abusive. Ethics are the actions taken to reach the ideal of doing right by the borrower. Penny's north star is the borrower's genuine interest: teach honestly, disclose fully, never pressure, and never place someone in a worse loan to benefit the lender."}, {"id": "mortgage-fraud", "title": "Mortgage Fraud — What Penny Will Never Do", "keywords": ["mortgage fraud", "occupancy fraud", "straw buyer", "fake income", "lie on application", "misrepresent", "use someone else's credit", "primary residence", "claim I'll live there", "inflated appraisal", "flipping", "foreclosure rescue", "MARS rule", "undisclosed debt", "early payment default"], "content": "The FBI defines mortgage fraud as a misstatement, misrepresentation, or omission about a loan that a lender relies on — any one of the three, including simply leaving information out, can be fraud. There are two categories: fraud for housing (usually a borrower fabricating income, falsifying assets, or misstating occupancy to qualify — fraud even if they intend to pay) and fraud for profit (industry insiders colluding across transactions, the costliest type). Occupancy fraud — claiming a rental will be a primary residence for better terms — is a form Penny never facilitates; the honest move is Fetti's real investment-property programs. A straw buyer uses someone else's identity and credit to obtain a loan — serious fraud for everyone involved. Other schemes: illegal property flipping (quick resale at an artificially inflated price on a fraudulent appraisal), builder bailout, silent seconds, double selling, short-sale flips, reverse-mortgage and affinity fraud, and foreclosure-rescue scams. The MARS Rule (Regulation O) makes it illegal for a foreclosure-relief provider to charge upfront fees or to tell a borrower to stop talking to their servicer, and requires clear disclosures — Penny warns borrowers about anyone doing the opposite. Failing to list a debt not on the credit report is an Ability-to-Repay violation and fraud. Loan officers cross-check names, addresses, and figures across documents; a single red flag isn't proof, but several together may signal fraud, and if something looks fraudulent it's reported to a manager or via a SAR. Penny always steers borrowers to the truthful, legitimate path."}, {"id": "servicing-transfer", "title": "Servicing Transfers — When Your Loan Gets Sold", "keywords": ["servicing transfer", "loan sold", "who do I pay", "new servicer", "goodbye letter", "hello letter", "my loan was transferred", "different company", "late fee grace", "payment address changed", "does my rate change", "secondary market"], "content": "After a loan closes, the loan and/or its servicing rights (who collects the payment) can be sold on the secondary market to Fannie Mae, Freddie Mac, Ginnie Mae, or other investors — this is normal and common, and the borrower's loan terms do not change. A mortgage servicer collects the monthly payment, pays the investor, and manages the escrow account. RESPA requires the lender to disclose on the Loan Estimate (within 3 business days of application) that servicing may be transferred; the LE's servicing line replaces the old separate servicing disclosure and tells the borrower whether the originating lender will keep servicing or transfer it. Mortgage brokers cannot service loans. When servicing actually transfers, the former ('old') servicer sends a 'goodbye letter' at least 15 days before the effective date, and the new servicer sends a 'hello letter' within 15 days after, with the new contact and payment details. Critically, for 60 days after the transfer, no late fee or delinquency mark may be imposed on a borrower who paid the old servicer on time by mistake. Penny reassures borrowers that a transfer is routine, that their rate, balance, and terms stay exactly the same, that they'll receive written notice from both servicers, and that the 60-day grace period protects them if a payment goes to the wrong place during the switch. She never treats a servicing transfer as a change to the loan itself."}];

export const KB_FAQS: { q: string; a: string; topic: string }[] = [{"q": "How much do I need to put down?", "a": "It depends on the loan. A VA loan for an eligible veteran and a USDA rural loan can be zero down. FHA is as little as 3.5% down, and a conventional loan can go as low as 3% down. Putting less than 20% down on a conventional loan means you'll carry mortgage insurance until you build enough equity. I can walk you through which programs fit, and a licensed loan officer will confirm the exact numbers for your situation.", "topic": "down-payment"}, {"q": "What credit score do I need to qualify?", "a": "Different programs have different floors. Conventional usually wants at least 620. FHA can go down to 580 for the 3.5% down option, or 500 with more down. VA and USDA don't set a hard minimum, though many lenders look for around 620. We pull all three bureaus and use your middle score. If your credit needs work, I can point you toward what helps most, but I can't promise a score or an approval.", "topic": "credit-qualifying-scores"}, {"q": "What's the difference between FHA mortgage insurance and PMI?", "a": "Both protect the lender, but they work differently. PMI is on conventional loans when you put down less than 20%, it comes from a private insurer, and it can come off — you can request it at 20% equity and it automatically ends at 22%. FHA has its own mortgage insurance, an upfront piece plus a monthly piece, and on most FHA loans that monthly premium stays for the life of the loan. The usual way to get rid of it is to refinance into a conventional loan once you have enough equity.", "topic": "pmi-mip"}, {"q": "Can I use gift money for my down payment?", "a": "Yes. Gift funds are allowed, usually from a family member, a significant other, or an employer, as long as there's truly no expectation of repayment. The person giving it signs a simple gift letter with their name, your relationship, the amount, and a statement that it doesn't need to be paid back. On an FHA loan a gift can even cover your entire down payment. We just need to document where it came from.", "topic": "assets-reserves-gifts"}, {"q": "Do I have to be at the same job for two years?", "a": "Not necessarily the same employer, but we generally look for a two-year history in the same line of work. Changing jobs within your field is usually fine, and gaps can be explained. If your income is commission, bonus, or overtime, we average it over two years. FHA can be a bit more flexible. Bring what you have and we'll figure out how it documents.", "topic": "income-documentation"}, {"q": "I'm self-employed — how does that work?", "a": "If you own 25% or more of your business, you're treated as self-employed, which means we look at both your personal and business tax returns and qualify you on your net income after write-offs, not your gross. We generally want a two-year history. If your returns understate what you really earn, ask me about a bank-statement loan, which qualifies you from your deposits instead. Either way the underwriter makes the final income call.", "topic": "self-employed-income"}, {"q": "What does a 5/1 ARM mean?", "a": "On a 5/1 ARM, your starting rate holds for the first five years, then the rate can adjust once a year after that. The rate is built from an index that moves with the market plus a fixed margin. There are caps that limit how much it can change at each adjustment and over the life of the loan. One thing I'm careful to say: an ARM's early period is a start rate that stays the same for a while — I'm not allowed to call any part of an ARM 'fixed,' because they're two different products.", "topic": "arm-vs-fixed"}, {"q": "What's the difference between the interest rate and the APR?", "a": "The interest rate is what's used to figure your monthly principal-and-interest payment. The APR is a broader number — it rolls the interest together with the loan's finance charges, like lender fees and mortgage insurance, into one annual figure so you can compare loan offers apples to apples. Because it includes those costs, the APR is normally a little higher than the note rate. I can explain how it's built, but I don't quote specific rates or APRs — a licensed loan officer does that.", "topic": "loan-process-timeline"}, {"q": "When will I get my Loan Estimate?", "a": "Once we have your complete application — that's six things: property address, loan amount, your income, an estimated property value, your name, and your Social Security number — you'll get your Loan Estimate within three business days. It lays out the loan terms and costs. After you review it, you tell us you want to proceed, and only then can we charge anything beyond a credit-report fee.", "topic": "loan-process-timeline"}, {"q": "Can I see the final numbers before I sign at closing?", "a": "Yes, absolutely. You'll get your Closing Disclosure with the final terms and costs at least three business days before you sign. That waiting period is built in on purpose so you have time to review everything and compare it to your Loan Estimate. If something big changes — like the loan product or the APR moving too much — that three-day clock can reset.", "topic": "closing-funding"}, {"q": "How long after a bankruptcy or foreclosure can I buy again?", "a": "It varies by program. After a Chapter 7 bankruptcy, FHA and VA generally want two years, USDA three years, and conventional four years. After a foreclosure, it's about three years for FHA, two for VA, three for USDA, and seven for conventional; short sales are usually shorter. Chapter 13 waits can be shorter and sometimes start after about a year of on-time plan payments. Extenuating circumstances can shorten some of these.", "topic": "credit-qualifying-scores"}, {"q": "If I sign my refinance, can I change my mind and cancel?", "a": "On a refinance of your primary home, yes — you get a three-business-day right to cancel after you sign, and the loan doesn't fund until that window passes. Anyone on title can cancel, and if one person cancels it's off for everyone. Just note this rescission right applies only to refinances of your main home — not to a purchase, a second home, or an investment property.", "topic": "refinance-cashout-heloc"}, {"q": "What's the difference between getting pre-qualified and pre-approved?", "a": "Pre-qualification is a quick, informal estimate based on what you tell me — a good starting conversation. Pre-approval is stronger: you send in documentation, we pull credit, and the lender issues a conditional commitment that sellers take much more seriously when you make an offer. Neither one is a final approval, though — that comes from the underwriter after a full review of your file.", "topic": "pre-approval-vs-prequal"}, {"q": "The appraisal came in low — can you just get the appraiser to raise the number?", "a": "No, and by law I can't even try. Appraisers are independent, and no one in the deal is allowed to pressure them or influence the value. What we can do is look at options: you might renegotiate the price with the seller, submit additional comparable sales for the appraiser to reconsider through the appraisal company, or bring a little more cash to cover the gap. I'll help you weigh those.", "topic": "appraisal"}, {"q": "Do you make more money if you put me in a more expensive loan or a higher rate?", "a": "No. The rules prohibit paying a loan originator based on your rate, loan program, or terms, and they ban steering you into something worse for someone's benefit. My job is to match you with the loan that genuinely fits. Fetti is an Equal Housing Opportunity lender — everyone qualified is welcome to apply, and decisions are based on your credit and the program guidelines, never on who you are.", "topic": "loan-process-timeline"}, {"q": "What's the difference between the interest rate and the APR?", "a": "Great question, it trips a lot of people up. Your interest rate is the number your monthly payment is built from. The APR is a bigger-picture number: it rolls that interest together with the lender and loan-related closing costs and expresses the whole thing as one yearly rate, so you can compare offers apples to apples. That's why the APR usually comes out a little higher than the rate. I won't throw numbers at you, but both are laid out clearly on your Loan Estimate, and a licensed loan officer can walk you through yours.", "topic": "tila-regz-apr"}, {"q": "When will I get my Loan Estimate, and how fast can we close?", "a": "Once we have your complete application, which is just six items, the law gives us three business days to get your Loan Estimate to you, and often much sooner. There's a built-in protection too: the loan can't close sooner than seven business days after that estimate goes out, so you always have time to review. And you'll get your Closing Disclosure at least three business days before you sign. It's all designed so you're never rushed.", "topic": "disclosures-le-cd-trid"}, {"q": "If I sign the Loan Estimate, am I locked into the loan?", "a": "Not at all. Signing the Loan Estimate just confirms you received it, that's it. You're not committed until you sign the actual closing documents at the end, like the Note and the Mortgage. So please review it, compare it with other lenders, and ask me anything. There's no obligation, and shopping around is a smart move.", "topic": "right-to-shop"}, {"q": "Do I have to pay anything upfront just to get started?", "a": "The only thing we can charge before you tell us you want to move forward is a reasonable credit report fee. We can't collect an application or appraisal fee until you've reviewed your Loan Estimate and given us your intent to proceed. That protects you in case you decide this isn't the right fit.", "topic": "right-to-shop"}, {"q": "Can I change my mind and cancel after I sign?", "a": "It depends on the type of loan. On a refinance or a home-equity loan on the home you live in as your primary residence, yes, you get a three-business-day right to cancel, called rescission. On a purchase, or on a second home or an investment property, there isn't a rescission window. I can tell you exactly which applies to your situation.", "topic": "right-of-rescission"}, {"q": "My spouse isn't on the loan. Can they cancel it?", "a": "On a loan that has a rescission right, yes. Anyone who holds an ownership interest in the home can cancel during that three-day window, even if they're not on the loan itself, and if one person cancels, it cancels for everyone. It's a protection for everybody who owns the home.", "topic": "right-of-rescission"}, {"q": "I got a refund check from my escrow account. Why?", "a": "That's a good sign, not a mistake. Your servicer reviews your escrow account once a year, and if it's holding more than the rules allow, by fifty dollars or more, they're required to send that surplus back to you. So that check is just your account balancing out.", "topic": "respa-regx"}, {"q": "How do I know you're not steering me into a loan just to make more money?", "a": "Fair thing to ask, and the rules actually protect you here. By law, how a loan officer is paid can't go up based on your rate, your loan program, your term, or the features of the loan, so there's no incentive to push you anywhere. Our job is to show you the options you qualify for, including the lower-cost and lower-risk ones, and help you choose what fits you best.", "topic": "udaap-ethics"}, {"q": "Can I just tell you I'll live in the property to get better terms, even though I'm renting it out?", "a": "I appreciate you asking me straight, so I'll be just as straight with you. How you'll use the home has to be accurate on the application, because that's what decides which program you fit. Saying you'll live somewhere you won't is occupancy misrepresentation, and it's treated as mortgage fraud even if you fully intend to pay. Here's the good news: Fetti has real investment-property programs built for rentals, so we don't have to bend a thing. We just put you in the lane that actually fits.", "topic": "mortgage-fraud"}, {"q": "My credit's rough. Can I just use my cousin's name and credit to get the loan?", "a": "I really appreciate you trusting me with that, and I want to protect you here. Using someone else's identity or credit to get a mortgage is what's called a straw buyer, and it's a serious form of mortgage fraud for everyone involved, your cousin included. Let's not go there. Instead, let me look at what you actually qualify for today, and if we need to, we'll build a short plan to get you ready.", "topic": "mortgage-fraud"}, {"q": "I'm worried I won't qualify because I'm on public assistance. Should I even apply?", "a": "Please don't count yourself out. By law, receiving public assistance or benefits can never be held against you, and we can't refuse your application over it. We're an Equal Housing Opportunity lender, and we look at whether income is enough and expected to continue, that's it. Let's actually run your situation and see what fits.", "topic": "ecoa-regb-fair-lending"}, {"q": "Can you use the child support I receive to help me qualify?", "a": "Here's how it works: I'm actually not allowed to ask you about child support or alimony you receive. But if you'd like it counted toward qualifying and you tell me about it voluntarily, then yes, we can consider it. So it's entirely your call whether to bring it into the picture.", "topic": "ecoa-regb-fair-lending"}, {"q": "Are you licensed? How do I check?", "a": "Absolutely, and I'd encourage you to verify it. Fetti Financial Services is a licensed mortgage company, NMLS number 2267023, and every licensed loan officer has their own NMLS ID on the application and disclosures. You can look us up for free on the NMLS Consumer Access website anytime. And just so you know, I'm Fetti's AI assistant helping you get started; a licensed human handles anything that requires a license.", "topic": "safe-nmls-licensing"}, {"q": "A company said they can stop my foreclosure if I pay upfront and stop talking to my lender. Is that safe?", "a": "Please be careful with that one, it trips several alarms for me. Under the federal rules for foreclosure-relief companies, they can't charge an upfront fee before your lender actually puts a written offer in front of you, they can't tell you to stop talking to your servicer, and they have to tell you plainly that they're not the government and not your lender. Anyone doing the opposite is a red flag. Keep talking to your servicer directly, and let me help you look at legitimate options.", "topic": "mortgage-fraud"}, {"q": "My loan got sold to a new company. Did my rate or terms change?", "a": "Nope, nothing about your actual loan changes, that's very common in this industry. If your servicing transfers, you'll get a goodbye letter from the old company and a hello letter from the new one, and there's a sixty-day grace period where you can't be hit with a late fee if you accidentally paid the old servicer on time. Your rate, balance, and terms all stay exactly the same.", "topic": "servicing-transfer"}];

// Lightweight keyword retrieval — no embeddings, phone-call fast. Scores each
// section by how many of its keywords (and title words) appear in the borrower's
// text, returns the top-n. Returns [] when nothing matches (caller falls back to
// the model's own knowledge + the CORE blocks already in the prompt).
export function retrieveKB(query: string, n = 3): KBSection[] {
  const q = " " + (query || "").toLowerCase().replace(/[^a-z0-9%\s.]/g, " ").replace(/\s+/g, " ") + " ";
  if (q.trim().length < 3) return [];
  const scored = KB_SECTIONS.map((s) => {
    let score = 0;
    for (const kw of s.keywords) {
      const k = kw.toLowerCase().trim();
      if (!k) continue;
      // multi-word keyword: substring match; single short word: whole-word match
      if (k.includes(" ")) { if (q.includes(k)) score += 3; }
      else if (k.length >= 3 && q.includes(" " + k)) score += (q.includes(" " + k + " ") ? 2 : 1);
    }
    for (const w of s.title.toLowerCase().split(/[^a-z0-9]+/)) {
      if (w.length >= 4 && q.includes(" " + w)) score += 1;
    }
    return { s, score };
  }).filter((x) => x.score > 0).sort((a, b) => b.score - a.score);
  return scored.slice(0, n).map((x) => x.s);
}

// Format retrieved sections as a compact system note for a single turn.
export function kbContextFor(query: string, n = 3): string {
  const hits = retrieveKB(query, n);
  if (!hits.length) return "";
  return "RELEVANT KNOWLEDGE (accurate reference for THIS question — teach it in your own warm, spoken words; never quote a specific rate, APR, payment, or term):\n" +
    hits.map((h) => `• ${h.title}: ${h.content}`).join("\n");
}
